// ============================================================================
// CSV Parser Library
// ============================================================================

/** Configuration options for the CSV parser */
export interface CSVOptions {
  /** Field delimiter character (default: ',') */
  delimiter?: string;
  /** Quote character for wrapping fields (default: '"') */
  quote?: string;
  /** Line separator (default: auto-detect \r\n, \r, or \n) */
  lineSeparator?: string;
  /** Whether to automatically coerce types (default: true) */
  typeCoercion?: boolean;
}

/** Represents a parsing error on a specific row */
export interface CSVError {
  row: number;
  message: string;
}

/** A single parsed row as a record of column name -> value */
export type CSVRow = Record<string, unknown>;

/** The result object returned by parseCSV */
export interface CSVResult {
  /** Parsed data rows as an array of objects keyed by header names */
  rows: CSVRow[];
  /** Column header names */
  headers: string[];
  /** Collected parsing errors (malformed rows, etc.) */
  errors: CSVError[];

  /** Return only rows matching the predicate */
  filter(predicate: (row: CSVRow) => boolean): CSVRow[];
  /** Sum all numeric values in the given column */
  sum(column: string): number;
  /** Average all numeric values in the given column */
  average(column: string): number;
  /** Count total data rows */
  count(): number;
  /** Group rows by the values in the given column */
  groupBy(column: string): Map<unknown, CSVRow[]>;
}

// ============================================================================
// Internal helpers
// ============================================================================

/**
 * Coerce a raw string value to its detected JS type.
 *  - "" / "null" / "NULL" → null
 *  - "true"/"false" (case-insensitive) → boolean
 *  - Numeric strings → number
 *  - Everything else → string (trimmed)
 */
function coerceValue(raw: string): unknown {
  const trimmed = raw.trim();

  // Null detection: empty string or literal null/NULL
  if (trimmed === "" || trimmed.toLowerCase() === "null") {
    return null;
  }

  // Boolean detection (case-insensitive)
  if (trimmed.toLowerCase() === "true") return true;
  if (trimmed.toLowerCase() === "false") return false;

  // Number detection – must be the entire string, no trailing garbage
  // Handles integers, floats, negative numbers, and scientific notation
  if (/^-?(\d+\.?\d*|\.\d+)([eE][+-]?\d+)?$/.test(trimmed)) {
    const num = Number(trimmed);
    if (!Number.isNaN(num)) return num;
  }

  return trimmed;
}

/**
 * Split a single CSV line into field values, respecting quoted fields.
 * Returns the array of raw string values for each field.
 *
 * This is a character-by-character state-machine parser that correctly
 * handles:
 *  - Quoted fields (may contain delimiters and newlines)
 *  - Escaped quotes (doubled quote character inside a quoted field)
 *  - Unquoted fields
 */
function parseRow(
  input: string,
  startIndex: number,
  delimiter: string,
  quote: string,
): { fields: string[]; nextIndex: number; error?: string } {
  const fields: string[] = [];
  let current = "";
  let i = startIndex;
  let inQuotes = false;
  let fieldHadQuotes = false;
  let error: string | undefined;

  while (i < input.length) {
    const ch = input[i];

    if (inQuotes) {
      if (ch === quote) {
        // Look ahead: doubled quote = escaped literal quote
        if (i + 1 < input.length && input[i + 1] === quote) {
          current += quote;
          i += 2;
          continue;
        }
        // End of quoted section
        inQuotes = false;
        i++;
        continue;
      }
      // Any other character inside quotes, including newlines
      current += ch;
      i++;
      continue;
    }

    // Not inside quotes
    if (ch === quote) {
      if (current.length === 0) {
        // Start of a quoted field
        inQuotes = true;
        fieldHadQuotes = true;
        i++;
        continue;
      } else {
        // Quote in the middle of an unquoted field — malformed, but don't crash
        error = `Unexpected quote character in unquoted field`;
        current += ch;
        i++;
        continue;
      }
    }

    if (ch === delimiter) {
      fields.push(current);
      current = "";
      fieldHadQuotes = false;
      i++;
      continue;
    }

    // Line terminators: \r\n, \r, or \n
    if (ch === "\r" || ch === "\n") {
      if (ch === "\r" && i + 1 < input.length && input[i + 1] === "\n") {
        i += 2;
      } else {
        i++;
      }
      fields.push(current);
      return { fields, nextIndex: i, error };
    }

    current += ch;
    i++;
  }

  // If we're still in quotes at EOF, that's an error
  if (inQuotes) {
    error = `Unterminated quoted field`;
  }

  fields.push(current);
  return { fields, nextIndex: i, error };
}

/**
 * Split the full input into logical rows using the state-machine parser.
 * Returns an array of { fields, rowNumber, error? } objects.
 */
function parseAllRows(
  input: string,
  delimiter: string,
  quote: string,
  lineSeparator?: string,
): { fields: string[]; rowNumber: number; error?: string }[] {
  // If a custom line separator is provided and there are no quoted fields
  // that might contain that separator, we can use a simpler split strategy.
  // However, to correctly handle quotes containing newlines we always use
  // the character-by-character parser.

  // If a custom lineSeparator is provided, pre-normalize the input so the
  // state machine (which looks for \r and \n) can detect line breaks.
  let normalized = input;
  if (lineSeparator && lineSeparator !== "\n" && lineSeparator !== "\r\n" && lineSeparator !== "\r") {
    // Replace custom separator with \n, but only outside quotes
    let result = "";
    let inQ = false;
    for (let i = 0; i < input.length; i++) {
      if (input[i] === quote) {
        if (inQ) {
          if (i + 1 < input.length && input[i + 1] === quote) {
            result += quote + quote;
            i++;
            continue;
          }
          inQ = false;
        } else {
          inQ = true;
        }
        result += input[i];
        continue;
      }
      if (
        !inQ &&
        input.substring(i, i + lineSeparator.length) === lineSeparator
      ) {
        result += "\n";
        i += lineSeparator.length - 1;
        continue;
      }
      result += input[i];
    }
    normalized = result;
  }

  const rows: { fields: string[]; rowNumber: number; error?: string }[] = [];
  let idx = 0;
  let rowNumber = 1;

  while (idx < normalized.length) {
    // Skip blank lines (consecutive line separators)
    if (normalized[idx] === "\n" || normalized[idx] === "\r") {
      if (normalized[idx] === "\r" && idx + 1 < normalized.length && normalized[idx + 1] === "\n") {
        idx += 2;
      } else {
        idx++;
      }
      rowNumber++;
      continue;
    }

    const result = parseRow(normalized, idx, delimiter, quote);
    rows.push({ fields: result.fields, rowNumber, error: result.error });
    idx = result.nextIndex;
    rowNumber++;
  }

  return rows;
}

// ============================================================================
// Main entry point
// ============================================================================

/**
 * Parse a CSV string into a structured result with data rows, headers,
 * error collection, and convenience methods for filtering and aggregation.
 */
export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator;
  const shouldCoerce = options?.typeCoercion !== false; // default true

  const errors: CSVError[] = [];

  // Handle empty / whitespace-only input
  if (!input || input.trim().length === 0) {
    return buildResult([], [], errors);
  }

  // Parse all logical rows
  const parsed = parseAllRows(input, delimiter, quote, lineSeparator);

  if (parsed.length === 0) {
    return buildResult([], [], errors);
  }

  // First row is always headers
  const headerRow = parsed[0];
  const headers = headerRow.fields.map((h) => h.trim());

  if (headerRow.error) {
    errors.push({ row: headerRow.rowNumber, message: `Header row: ${headerRow.error}` });
  }

  const rows: CSVRow[] = [];

  for (let i = 1; i < parsed.length; i++) {
    const { fields, rowNumber, error } = parsed[i];

    // Collect any parsing error from the row itself
    if (error) {
      errors.push({ row: rowNumber, message: error });
    }

    // Check field count mismatch
    if (fields.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });
      // Still attempt to build a row object with available data
    }

    const row: CSVRow = {};
    for (let j = 0; j < headers.length; j++) {
      const raw = j < fields.length ? fields[j] : "";
      row[headers[j]] = shouldCoerce ? coerceValue(raw) : raw;
    }
    rows.push(row);
  }

  return buildResult(rows, headers, errors);
}

/** Construct the CSVResult object with all its methods. */
function buildResult(
  rows: CSVRow[],
  headers: string[],
  errors: CSVError[],
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: CSVRow) => boolean): CSVRow[] {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
        }
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, CSVRow[]> {
      const groups = new Map<unknown, CSVRow[]>();
      for (const row of rows) {
        const key = row[column];
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key)!.push(row);
      }
      return groups;
    },
  };
}

// ============================================================================
// CSV Parser – Comprehensive Test Suite
// ============================================================================
// No external test framework. Every assertion throws on failure.
// Run with: npx ts-node csv-parser.test.ts   (or tsx, etc.)
// ============================================================================

import { parseCSV, CSVResult, CSVRow } from "./csv-parser";

// ─── Tiny assertion helpers ─────────────────────────────────────────────────

let passed = 0;
let failed = 0;
const failures: string[] = [];

function assert(condition: boolean, message: string): void {
  if (!condition) {
    failed++;
    failures.push(message);
    console.error(`  ✗ ${message}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function assertEqual(actual: unknown, expected: unknown, label: string): void {
  const a = JSON.stringify(actual);
  const e = JSON.stringify(expected);
  if (a !== e) {
    failed++;
    const msg = `${label}\n      expected: ${e}\n      actual:   ${a}`;
    failures.push(msg);
    console.error(`  ✗ ${msg}`);
  } else {
    passed++;
    console.log(`  ✓ ${label}`);
  }
}

function assertClose(actual: number, expected: number, label: string, epsilon = 1e-9): void {
  if (Math.abs(actual - expected) > epsilon) {
    failed++;
    const msg = `${label} — expected ≈${expected}, got ${actual}`;
    failures.push(msg);
    console.error(`  ✗ ${msg}`);
  } else {
    passed++;
    console.log(`  ✓ ${label}`);
  }
}

function section(name: string): void {
  console.log(`\n━━━ ${name} ━━━`);
}

// ============================================================================
// 1. BASIC PARSING
// ============================================================================
section("Basic Parsing");

(() => {
  const csv = `name,age,city
Alice,30,New York
Bob,25,Los Angeles
Charlie,35,Chicago`;

  const result = parseCSV(csv);
  assertEqual(result.headers, ["name", "age", "city"], "headers parsed correctly");
  assertEqual(result.rows.length, 3, "three data rows");
  assertEqual(result.rows[0]["name"], "Alice", "first row name");
  assertEqual(result.rows[0]["age"], 30, "first row age (number)");
  assertEqual(result.rows[0]["city"], "New York", "first row city");
  assertEqual(result.rows[1]["name"], "Bob", "second row name");
  assertEqual(result.rows[2]["city"], "Chicago", "third row city");
  assertEqual(result.errors.length, 0, "no errors on well-formed input");
})();

// ============================================================================
// 2. QUOTED FIELDS WITH COMMAS
// ============================================================================
section("Quoted Fields with Commas");

(() => {
  const csv = `name,address,city
Alice,"123 Main St, Apt 4",Springfield
Bob,"456 Oak Ave, Suite 100",Portland`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0]["address"], "123 Main St, Apt 4", "quoted field preserves comma");
  assertEqual(result.rows[1]["address"], "456 Oak Ave, Suite 100", "second quoted field");
  assertEqual(result.rows.length, 2, "correct row count with quoted commas");
  assertEqual(result.errors.length, 0, "no errors");
})();

(() => {
  const csv = `a,b,c
"hello, world",2,3
4,"foo, bar, baz",6`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0]["a"], "hello, world", "comma inside quotes (first field)");
  assertEqual(result.rows[1]["b"], "foo, bar, baz", "comma inside quotes (middle field)");
})();

// ============================================================================
// 3. ESCAPED QUOTES
// ============================================================================
section("Escaped Quotes");

(() => {
  const csv = `name,quote
Alice,"She said ""hello""!"
Bob,"He replied ""goodbye""."`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0]["quote"], 'She said "hello"!', "escaped double quotes parsed");
  assertEqual(result.rows[1]["quote"], 'He replied "goodbye".', "second row escaped quotes");
  assertEqual(result.errors.length, 0, "no errors");
})();

(() => {
  const csv = `value
""""
"a""b""c"`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0]["value"], '"', "four quotes become one literal quote");
  assertEqual(result.rows[1]["value"], 'a"b"c', "quotes interspersed in text");
})();

// ============================================================================
// 4. CUSTOM DELIMITERS
// ============================================================================
section("Custom Delimiters");

// Tab-separated
(() => {
  const tsv = `name\tage\tcity
Alice\t30\tNew York
Bob\t25\tPortland`;

  const result = parseCSV(tsv, { delimiter: "\t" });
  assertEqual(result.headers, ["name", "age", "city"], "TSV headers");
  assertEqual(result.rows[0]["name"], "Alice", "TSV first row name");
  assertEqual(result.rows[0]["age"], 30, "TSV first row age");
  assertEqual(result.rows.length, 2, "TSV row count");
})();

// Semicolon-separated
(() => {
  const csv = `name;age;city
Alice;30;London
Bob;25;Paris`;

  const result = parseCSV(csv, { delimiter: ";" });
  assertEqual(result.rows[0]["city"], "London", "semicolon delimiter: city");
  assertEqual(result.rows[1]["name"], "Bob", "semicolon delimiter: name");
})();

// Pipe-separated
(() => {
  const csv = `name|age
Alice|30
Bob|25`;

  const result = parseCSV(csv, { delimiter: "|" });
  assertEqual(result.rows[0]["name"], "Alice", "pipe delimiter");
  assertEqual(result.rows[0]["age"], 30, "pipe delimiter number");
})();

// Custom quote character (single quote)
(() => {
  const csv = `name,desc
Alice,'has a, comma'
Bob,'another, one'`;

  const result = parseCSV(csv, { quote: "'" });
  assertEqual(result.rows[0]["desc"], "has a, comma", "single-quote quoting");
  assertEqual(result.rows[1]["desc"], "another, one", "single-quote second row");
})();

// Custom line separator
(() => {
  const csv = `name,age|Alice,30|Bob,25`;

  const result = parseCSV(csv, { lineSeparator: "|" });
  assertEqual(result.headers, ["name", "age"], "custom line separator: headers");
  assertEqual(result.rows[0]["name"], "Alice", "custom line separator: first row");
  assertEqual(result.rows[1]["age"], 25, "custom line separator: second row");
})();

// ============================================================================
// 5. TYPE COERCION
// ============================================================================
section("Type Coercion");

// Integers
(() => {
  const csv = `val
0
1
-5
100
999999`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], 0, "integer 0");
  assertEqual(result.rows[1]["val"], 1, "integer 1");
  assertEqual(result.rows[2]["val"], -5, "negative integer");
  assertEqual(result.rows[3]["val"], 100, "integer 100");
  assertEqual(result.rows[4]["val"], 999999, "large integer");
})();

// Floats
(() => {
  const csv = `val
3.14
-0.5
.25
1.0
100.001`;

  const result = parseCSV(csv);
  assertClose(result.rows[0]["val"] as number, 3.14, "float 3.14");
  assertClose(result.rows[1]["val"] as number, -0.5, "float -0.5");
  assertClose(result.rows[2]["val"] as number, 0.25, "float .25");
  assertClose(result.rows[3]["val"] as number, 1.0, "float 1.0");
  assertClose(result.rows[4]["val"] as number, 100.001, "float 100.001");
})();

// Scientific notation
(() => {
  const csv = `val
1e10
2.5E3
1e-5`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], 1e10, "scientific 1e10");
  assertEqual(result.rows[1]["val"], 2.5e3, "scientific 2.5E3");
  assertClose(result.rows[2]["val"] as number, 1e-5, "scientific 1e-5");
})();

// Booleans
(() => {
  const csv = `val
true
false
TRUE
FALSE
True
False`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], true, "boolean true");
  assertEqual(result.rows[1]["val"], false, "boolean false");
  assertEqual(result.rows[2]["val"], true, "boolean TRUE");
  assertEqual(result.rows[3]["val"], false, "boolean FALSE");
  assertEqual(result.rows[4]["val"], true, "boolean True");
  assertEqual(result.rows[5]["val"], false, "boolean False");
})();

// Null values
(() => {
  const csv = `a,b,c
null,NULL,
test,null,`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0]["a"], null, "null lowercase → null");
  assertEqual(result.rows[0]["b"], null, "NULL uppercase → null");
  assertEqual(result.rows[0]["c"], null, "empty string → null");
  assertEqual(result.rows[1]["a"], "test", "non-null string preserved");
  assertEqual(result.rows[1]["b"], null, "null in second row");
  assertEqual(result.rows[1]["c"], null, "empty in second row");
})();

// String values stay as strings
(() => {
  const csv = `val
hello
world
abc123def
12abc`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], "hello", "plain string");
  assertEqual(result.rows[1]["val"], "world", "plain string 2");
  assertEqual(result.rows[2]["val"], "abc123def", "mixed alpha-num stays string");
  assertEqual(result.rows[3]["val"], "12abc", "starts with number but is string");
})();

// Type coercion disabled
(() => {
  const csv = `val
42
true
null`;

  const result = parseCSV(csv, { typeCoercion: false });
  assertEqual(result.rows[0]["val"], "42", "no coercion: number stays string");
  assertEqual(result.rows[1]["val"], "true", "no coercion: bool stays string");
  assertEqual(result.rows[2]["val"], "null", "no coercion: null stays string");
})();

// ============================================================================
// 6. ERROR HANDLING – MALFORMED ROWS
// ============================================================================
section("Error Handling – Malformed Rows");

// Too few fields
(() => {
  const csv = `name,age,city
Alice,30,New York
Bob,25
Charlie,35,Chicago`;

  const result = parseCSV(csv);
  assertEqual(result.rows.length, 3, "all rows returned even with malformed one");
  assert(result.errors.length > 0, "errors collected for malformed row");
  assert(
    result.errors.some((e) => e.row === 3 && e.message.includes("Expected 3 fields but got 2")),
    "error identifies correct row (3) and field count mismatch"
  );
  // The malformed row should still have accessible data
  assertEqual(result.rows[1]["name"], "Bob", "malformed row: accessible field");
  assertEqual(result.rows[1]["city"], null, "malformed row: missing field becomes null");
})();

// Too many fields
(() => {
  const csv = `a,b
1,2
3,4,5
6,7`;

  const result = parseCSV(csv);
  assert(result.errors.some((e) => e.row === 3), "too-many-fields error on row 3");
  assertEqual(result.rows.length, 3, "all rows still present");
})();

// Unterminated quote
(() => {
  const csv = `name,val
Alice,"unclosed quote
Bob,normal`;

  const result = parseCSV(csv);
  assert(result.errors.length > 0, "unterminated quote produces error");
  assert(
    result.errors.some((e) => e.message.toLowerCase().includes("unterminated")),
    "error message mentions unterminated"
  );
})();

// Multiple errors in one file
(() => {
  const csv = `a,b,c
1,2
3,4,5,6
7,8,9`;

  const result = parseCSV(csv);
  assert(result.errors.length >= 2, "multiple errors collected");
  assertEqual(result.rows.length, 3, "all data rows present despite errors");
})();

// ============================================================================
// 7. FILTER FUNCTIONALITY
// ============================================================================
section("Filter Functionality");

(() => {
  const csv = `name,age,city
Alice,30,New York
Bob,25,Portland
Charlie,35,New York
Diana,28,Portland`;

  const result = parseCSV(csv);

  const nyResidents = result.filter((row) => row["city"] === "New York");
  assertEqual(nyResidents.length, 2, "filter: 2 New York residents");
  assertEqual(nyResidents[0]["name"], "Alice", "filter: first match is Alice");
  assertEqual(nyResidents[1]["name"], "Charlie", "filter: second match is Charlie");

  const over28 = result.filter((row) => (row["age"] as number) > 28);
  assertEqual(over28.length, 2, "filter: 2 people over 28");

  const noMatch = result.filter((row) => row["city"] === "London");
  assertEqual(noMatch.length, 0, "filter: no matches returns empty array");

  const all = result.filter(() => true);
  assertEqual(all.length, 4, "filter: always-true returns all rows");
})();

// ============================================================================
// 8. AGGREGATION METHODS
// ============================================================================
section("Aggregation – sum()");

(() => {
  const csv = `product,price,quantity
Widget,10.5,100
Gadget,25.0,50
Doohickey,5.75,200`;

  const result = parseCSV(csv);
  assertClose(result.sum("price"), 41.25, "sum of price column");
  assertClose(result.sum("quantity"), 350, "sum of quantity column");
})();

(() => {
  const csv = `name,score
Alice,null
Bob,80
Charlie,`;

  const result = parseCSV(csv);
  assertClose(result.sum("score"), 80, "sum ignores null values");
  assertClose(result.sum("name"), 0, "sum of non-numeric column is 0");
})();

(() => {
  const csv = `val
-10
20
-5
15`;

  const result = parseCSV(csv);
  assertClose(result.sum("val"), 20, "sum with negative numbers");
})();

section("Aggregation – average()");

(() => {
  const csv = `name,score
Alice,90
Bob,80
Charlie,70`;

  const result = parseCSV(csv);
  assertClose(result.average("score"), 80, "average of scores");
})();

(() => {
  const csv = `name,score
Alice,null
Bob,80
Charlie,`;

  const result = parseCSV(csv);
  assertClose(result.average("score"), 80, "average ignores nulls");
})();

(() => {
  const csv = `name
Alice
Bob`;

  const result = parseCSV(csv);
  assertEqual(result.average("name"), 0, "average of non-numeric column is 0");
  assertEqual(result.average("nonexistent"), 0, "average of nonexistent column is 0");
})();

section("Aggregation – count()");

(() => {
  const csv = `name,age
Alice,30
Bob,25
Charlie,35`;

  const result = parseCSV(csv);
  assertEqual(result.count(), 3, "count returns 3");
})();

(() => {
  const csv = `name`;
  const result = parseCSV(csv);
  assertEqual(result.count(), 0, "count with no data rows returns 0");
})();

section("Aggregation – groupBy()");

(() => {
  const csv = `name,dept,salary
Alice,Engineering,100000
Bob,Marketing,80000
Charlie,Engineering,120000
Diana,Marketing,90000
Eve,Engineering,110000`;

  const result = parseCSV(csv);
  const groups = result.groupBy("dept");

  assertEqual(groups.size, 2, "groupBy: 2 departments");
  assertEqual(groups.get("Engineering")!.length, 3, "groupBy: 3 engineers");
