section("Error Handling â Malformed Rows");

// Too few fields
(() => {
  const csv = `name,age,city
Alice,30,New York
Bob,25
Charlie,35,Chicago`;

  const result = parseCSV(csv);
  assertEqual(result.rows.length, 3, "all rows returned even with malformed one");
  assert(result.errors.length > 0, "errors collected for malformed row");
  assert(
    result.errors.some((e) => e.row === 3 && e.message.includes("Expected 3 fields but got 2")),
    "error identifies correct row (3) and field count mismatch"
  );
  // The malformed row should still have accessible data
  assertEqual(result.rows[1]["name"], "Bob", "malformed row: accessible field");
  assertEqual(result.rows[1]["city"], null, "malformed row: missing field becomes null");
})();

// Too many fields
(() => {
