Alice,"unclosed quote
Bob,normal`;

  const result = parseCSV(csv);
  assert(result.errors.length > 0, "unterminated quote produces error");
  assert(
    result.errors.some((e) => e.message.toLowerCase().includes("unterminated")),
    "error message mentions unterminated"
  );
})();

// Multiple errors in one file
(() => {
  const csv = `a,b,c
1,2
3,4,5,6
7,8,9`;

