  assertEqual(result.average("missing"), 0, "average of nonexistent column is 0");
})();

section("Edge Cases – groupBy on nonexistent column");

(() => {
  const csv = `name
Alice
Bob`;

  const result = parseCSV(csv);
  const groups = result.groupBy("missing");
