  assertEqual(result.rows[0]["col0"], 0, "first column value");
  assertEqual(result.rows[0]["col499"], 499, "last column value");
})();

// ============================================================================
// SUMMARY
// ============================================================================
console.log("\n" + "=".repeat(60));
console.log(`RESULTS: ${passed} passed, ${failed} failed, ${passed + failed} total`);
if (failed > 0) {
  console.log("\nFailed tests:");
  for (const f of failures) {
    console.log(`  • ${f}`);
  }
  console.log("");
  process.exit(1);
} else {
  console.log("All tests passed! ✓");
  process.exit(0);
}

