// ============================================================================
// CSV Parser Library
// ============================================================================

/** Configuration options for the CSV parser */
export interface CSVOptions {
  /** Field delimiter character (default: ',') */
  delimiter?: string;
  /** Quote character for wrapping fields (default: '"') */
  quote?: string;
  /** Line separator (default: auto-detect \r\n, \r, or \n) */
  lineSeparator?: string;
  /** Whether to automatically coerce types (default: true) */
  typeCoercion?: boolean;
}

/** Represents a parsing error on a specific row */
export interface CSVError {
  row: number;
  message: string;
}

/** A single parsed row as a record of column name -> value */
export type CSVRow = Record<string, unknown>;

/** The result object returned by parseCSV */
export interface CSVResult {
  /** Parsed data rows as an array of objects keyed by header names */
  rows: CSVRow[];
  /** Column header names */
  headers: string[];
  /** Collected parsing errors (malformed rows, etc.) */
  errors: CSVError[];

  /** Return only rows matching the predicate */
  filter(predicate: (row: CSVRow) => boolean): CSVRow[];
  /** Sum all numeric values in the given column */
  sum(column: string): number;
  /** Average all numeric values in the given column */
  average(column: string): number;
  /** Count total data rows */
  count(): number;
  /** Group rows by the values in the given column */
  groupBy(column: string): Map<unknown, CSVRow[]>;
}

// ============================================================================
// Internal helpers
// ============================================================================

/**
 * Coerce a raw string value to its detected JS type.
 *  - "" / "null" / "NULL" → null
 *  - "true"/"false" (case-insensitive) → boolean
 *  - Numeric strings → number
 *  - Everything else → string (trimmed)
 */
function coerceValue(raw: string): unknown {
  const trimmed = raw.trim();

  // Null detection: empty string or literal null/NULL
  if (trimmed === "" || trimmed.toLowerCase() === "null") {
    return null;
  }

  // Boolean detection (case-insensitive)
  if (trimmed.toLowerCase() === "true") return true;
  if (trimmed.toLowerCase() === "false") return false;

  // Number detection – must be the entire string, no trailing garbage
  // Handles integers, floats, negative numbers, and scientific notation
  if (/^-?(\d+\.?\d*|\.\d+)([eE][+-]?\d+)?$/.test(trimmed)) {
    const num = Number(trimmed);
    if (!Number.isNaN(num)) return num;
  }

  return trimmed;
}

/**
 * Split a single CSV line into field values, respecting quoted fields.
 * Returns the array of raw string values for each field.
 *
 * This is a character-by-character state-machine parser that correctly
 * handles:
 *  - Quoted fields (may contain delimiters and newlines)
 *  - Escaped quotes (doubled quote character inside a quoted field)
 *  - Unquoted fields
 */
function parseRow(
  input: string,
  startIndex: number,
  delimiter: string,
  quote: string,
): { fields: string[]; nextIndex: number; error?: string } {
  const fields: string[] = [];
  let current = "";
  let i = startIndex;
  let inQuotes = false;
  let fieldHadQuotes = false;
  let error: string | undefined;

  while (i < input.length) {
    const ch = input[i];

    if (inQuotes) {
      if (ch === quote) {
        // Look ahead: doubled quote = escaped literal quote
        if (i + 1 < input.length && input[i + 1] === quote) {
          current += quote;
          i += 2;
          continue;
        }
        // End of quoted section
        inQuotes = false;
        i++;
        continue;
      }
      // Any other character inside quotes, including newlines
      current += ch;
      i++;
      continue;
    }

    // Not inside quotes
    if (ch === quote) {
      if (current.length === 0) {
        // Start of a quoted field
        inQuotes = true;
        fieldHadQuotes = true;
        i++;
        continue;
      } else {
        // Quote in the middle of an unquoted field — malformed, but don't crash
        error = `Unexpected quote character in unquoted field`;
        current += ch;
        i++;
        continue;
      }
    }

    if (ch === delimiter) {
      fields.push(current);
      current = "";
      fieldHadQuotes = false;
      i++;
      continue;
    }

    // Line terminators: \r\n, \r, or \n
    if (ch === "\r" || ch === "\n") {
      if (ch === "\r" && i + 1 < input.length && input[i + 1] === "\n") {
        i += 2;
      } else {
        i++;
      }
      fields.push(current);
      return { fields, nextIndex: i, error };
    }

    current += ch;
    i++;
  }

  // If we're still in quotes at EOF, that's an error
  if (inQuotes) {
    error = `Unterminated quoted field`;
  }

  fields.push(current);
  return { fields, nextIndex: i, error };
}

/**
 * Split the full input into logical rows using the state-machine parser.
 * Returns an array of { fields, rowNumber, error? } objects.
 */
function parseAllRows(
  input: string,
  delimiter: string,
  quote: string,
  lineSeparator?: string,
): { fields: string[]; rowNumber: number; error?: string }[] {
  // If a custom line separator is provided and there are no quoted fields
  // that might contain that separator, we can use a simpler split strategy.
  // However, to correctly handle quotes containing newlines we always use
  // the character-by-character parser.

  // If a custom lineSeparator is provided, pre-normalize the input so the
  // state machine (which looks for \r and \n) can detect line breaks.
  let normalized = input;
  if (lineSeparator && lineSeparator !== "\n" && lineSeparator !== "\r\n" && lineSeparator !== "\r") {
    // Replace custom separator with \n, but only outside quotes
    let result = "";
    let inQ = false;
    for (let i = 0; i < input.length; i++) {
      if (input[i] === quote) {
        if (inQ) {
          if (i + 1 < input.length && input[i + 1] === quote) {
            result += quote + quote;
            i++;
            continue;
          }
          inQ = false;
        } else {
          inQ = true;
        }
        result += input[i];
        continue;
      }
      if (
        !inQ &&
        input.substring(i, i + lineSeparator.length) === lineSeparator
      ) {
        result += "\n";
        i += lineSeparator.length - 1;
        continue;
      }
      result += input[i];
    }
    normalized = result;
  }

  const rows: { fields: string[]; rowNumber: number; error?: string }[] = [];
  let idx = 0;
  let rowNumber = 1;

  while (idx < normalized.length) {
    // Skip blank lines (consecutive line separators)
    if (normalized[idx] === "\n" || normalized[idx] === "\r") {
      if (normalized[idx] === "\r" && idx + 1 < normalized.length && normalized[idx + 1] === "\n") {
        idx += 2;
      } else {
        idx++;
      }
      rowNumber++;
      continue;
    }

    const result = parseRow(normalized, idx, delimiter, quote);
    rows.push({ fields: result.fields, rowNumber, error: result.error });
    idx = result.nextIndex;
    rowNumber++;
  }

  return rows;
}

// ============================================================================
// Main entry point
// ============================================================================

/**
 * Parse a CSV string into a structured result with data rows, headers,
 * error collection, and convenience methods for filtering and aggregation.
 */
export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator;
  const shouldCoerce = options?.typeCoercion !== false; // default true

  const errors: CSVError[] = [];

  // Handle empty / whitespace-only input
  if (!input || input.trim().length === 0) {
    return buildResult([], [], errors);
  }

  // Parse all logical rows
  const parsed = parseAllRows(input, delimiter, quote, lineSeparator);

  if (parsed.length === 0) {
    return buildResult([], [], errors);
  }

  // First row is always headers
  const headerRow = parsed[0];
  const headers = headerRow.fields.map((h) => h.trim());

  if (headerRow.error) {
    errors.push({ row: headerRow.rowNumber, message: `Header row: ${headerRow.error}` });
  }

  const rows: CSVRow[] = [];

  for (let i = 1; i < parsed.length; i++) {
    const { fields, rowNumber, error } = parsed[i];

    // Collect any parsing error from the row itself
    if (error) {
      errors.push({ row: rowNumber, message: error });
    }

    // Check field count mismatch
    if (fields.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });
      // Still attempt to build a row object with available data
    }

    const row: CSVRow = {};
    for (let j = 0; j < headers.length; j++) {
      const raw = j < fields.length ? fields[j] : "";
      row[headers[j]] = shouldCoerce ? coerceValue(raw) : raw;
    }
    rows.push(row);
  }

  return buildResult(rows, headers, errors);
}

/** Construct the CSVResult object with all its methods. */
function buildResult(
  rows: CSVRow[],
  headers: string[],
  errors: CSVError[],
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: CSVRow) => boolean): CSVRow[] {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
        }
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, CSVRow[]> {
      const groups = new Map<unknown, CSVRow[]>();
      for (const row of rows) {
        const key = row[column];
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key)!.push(row);
      }
      return groups;
    },
  };
}
